import{_ as a,c as e,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const b=JSON.parse('{"title":"リリースノート: バージョン進化 | Antigravity-Manager","description":"Antigravity-Manager のバージョン進化方法を理解します。Settings ページでバージョンを確認して更新をチェックし、README Changelog で修正とリマインダーを確認し、/healthz でアップグレード後の可用性を検証します。","frontmatter":{"title":"リリースノート: バージョン進化 | Antigravity-Manager","sidebarTitle":"3 分でバージョン更新を理解","subtitle":"バージョン進化：README 内蔵 Changelog を基準とする","description":"Antigravity-Manager のバージョン進化方法を理解します。Settings ページでバージョンを確認して更新をチェックし、README Changelog で修正とリマインダーを確認し、/healthz でアップグレード後の可用性を検証します。","tags":["changelog","release","upgrade","troubleshooting"],"prerequisite":["start-installation","start-proxy-and-first-client"],"order":1},"headers":[],"relativePath":"ja/lbjlaq/Antigravity-Manager/changelog/release-notes/index.md","filePath":"ja/lbjlaq/Antigravity-Manager/changelog/release-notes/index.md"}'),n={name:"ja/lbjlaq/Antigravity-Manager/changelog/release-notes/index.md"};function l(i,t,d,s,g,h){return o(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="バージョン進化-readme-内蔵-changelog-を基準とする" tabindex="-1">バージョン進化：README 内蔵 Changelog を基準とする <a class="header-anchor" href="#バージョン進化-readme-内蔵-changelog-を基準とする" aria-label="Permalink to &quot;バージョン進化：README 内蔵 Changelog を基準とする&quot;">​</a></h1><p>Antigravity Tools をアップグレードする準備をしている場合、最も恐れているのは「更新されていないこと」ではなく、「更新してから互換性の変更に気づくこと」です。このページでは <strong>Antigravity Tools Changelog（バージョン進化）</strong> の読み方を明確にし、アップグレード前に判断できるようにします：今回の更新があなたにどのような影響を与えるか。</p><h2 id="学べること" tabindex="-1">学べること <a class="header-anchor" href="#学べること" aria-label="Permalink to &quot;学べること&quot;">​</a></h2><ul><li>Settings の About ページで現在のバージョンを素早く確認し、更新をチェックしてダウンロードエントリを取得する</li><li>README の Changelog で自分に影響のあるバージョン段落のみを読む（最初から最後まで読むのではなく）</li><li>アップグレード前に一つのことを行う：設定/モデルマッピングを手動で変更する必要があるというリマインダーがあるかどうかを確認する</li><li>アップグレード後に最小検証（<code>/healthz</code>）を一度実行し、プロキシがまだ使用できることを確認する</li></ul><h2 id="changelog-とは何か" tabindex="-1">Changelog とは何か？ <a class="header-anchor" href="#changelog-とは何か" aria-label="Permalink to &quot;Changelog とは何か？&quot;">​</a></h2><p><strong>Changelog</strong> はバージョン別に「今回何が変更されたか」を記録したリストです。Antigravity Tools はこれを README の「バージョン進化」に直接記述し、各バージョンで日付と重要な変更を明記します。アップグレード前に Changelog を確認すると、互換性の変更や回帰問題に遭遇する可能性を減らすことができます。</p><h2 id="このページをいつ使用するか" tabindex="-1">このページをいつ使用するか <a class="header-anchor" href="#このページをいつ使用するか" aria-label="Permalink to &quot;このページをいつ使用するか&quot;">​</a></h2><ul><li>旧バージョンから新バージョンにアップグレードする準備をしており、リスクポイントを事前に確認したい場合</li><li>特定の問題（例：429/0 Token/Cloudflared）に遭遇し、最近のバージョンで修正されたかどうかを確認したい場合</li><li>チームで統一バージョンを維持しており、同僚に「バージョン別に変更を確認する」方法を提供する必要がある場合</li></ul><h2 id="🎒-開始前の準備" tabindex="-1">🎒 開始前の準備 <a class="header-anchor" href="#🎒-開始前の準備" aria-label="Permalink to &quot;🎒 開始前の準備&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">アップグレードパスを事前に準備することをおすすめします</p><p>インストール/アップグレードの方法は多数あります（brew、Releases 手動ダウンロード、アプリ内更新）。まだ自分がどの方法を使用するか決めていない場合は、<strong><a href="/docs/opencodedocs/ja/lbjlaq/Antigravity-Manager/start/installation/">インストールとアップグレード：デスクトップ版のベストインストールパス（brew / releases）</a></strong> を確認してください。</p></div><h2 id="やってみよう" tabindex="-1">やってみよう <a class="header-anchor" href="#やってみよう" aria-label="Permalink to &quot;やってみよう&quot;">​</a></h2><h3 id="ステップ-1-about-ページで現在のバージョンを確認する" tabindex="-1">ステップ 1：About ページで現在のバージョンを確認する <a class="header-anchor" href="#ステップ-1-about-ページで現在のバージョンを確認する" aria-label="Permalink to &quot;ステップ 1：About ページで現在のバージョンを確認する&quot;">​</a></h3><p><strong>なぜ</strong> Changelog はバージョン別に整理されています。現在のバージョンを最初に知ることで、「どこから読み始めるべきか」がわかります。</p><p>操作パス：<strong>Settings</strong> → <strong>About</strong>。</p><p><strong>表示されるべきもの</strong>：ページタイトルエリアにアプリ名とバージョン番号が表示されます（例：<code>v3.3.49</code>）。</p><h3 id="ステップ-2-「更新をチェック」をクリックし、最新バージョンとダウンロードエントリを取得する" tabindex="-1">ステップ 2：「更新をチェック」をクリックし、最新バージョンとダウンロードエントリを取得する <a class="header-anchor" href="#ステップ-2-「更新をチェック」をクリックし、最新バージョンとダウンロードエントリを取得する" aria-label="Permalink to &quot;ステップ 2：「更新をチェック」をクリックし、最新バージョンとダウンロードエントリを取得する&quot;">​</a></h3><p><strong>なぜ</strong> まず「最新バージョン番号は何か」を知る必要があり、それから Changelog で中間のスキップされたバージョン段落を選び出すことができます。</p><p>About ページで「更新をチェック」をクリックします。</p><p><strong>表示されるべきもの</strong>：</p><ul><li>更新がある場合：「new version available」が提示され、ダウンロードボタン（<code>download_url</code> を開く）が表示されます</li><li>すでに最新の場合：「latest version」が提示されます</li></ul><h3 id="ステップ-3-readme-の-changelog-でスキップしたバージョンのみを確認する" tabindex="-1">ステップ 3：README の Changelog でスキップしたバージョンのみを確認する <a class="header-anchor" href="#ステップ-3-readme-の-changelog-でスキップしたバージョンのみを確認する" aria-label="Permalink to &quot;ステップ 3：README の Changelog でスキップしたバージョンのみを確認する&quot;">​</a></h3><p><strong>なぜ</strong> あなたは「現在のバージョンから最新バージョンまでの間」の変更のみに気にする必要があり、他の履歴バージョンはとりあえずスキップできます。</p><p>README を開き、<strong>「バージョン進化 (Changelog)」</strong> に移動し、最新バージョンから見始め、現在のバージョンが見えるまで下にスクロールします。</p><p><strong>表示されるべきもの</strong>：バージョンは <code>vX.Y.Z (YYYY-MM-DD)</code> の形式でリストされ、各バージョンにはグループ化された説明（例：コア修正/機能強化）があります。</p><h3 id="ステップ-4-アップグレード後に最小検証を一度行う" tabindex="-1">ステップ 4：アップグレード後に最小検証を一度行う <a class="header-anchor" href="#ステップ-4-アップグレード後に最小検証を一度行う" aria-label="Permalink to &quot;ステップ 4：アップグレード後に最小検証を一度行う&quot;">​</a></h3><p><strong>なぜ</strong> アップグレード後の最初の作業は「複雑なシナリオを実行する」ことではなく、プロキシが正常に起動し、クライアントが生きていることを確認することです。</p><p><strong><a href="/docs/opencodedocs/ja/lbjlaq/Antigravity-Manager/start/proxy-and-first-client/">ローカルリバースプロキシの起動と最初のクライアント接続（/healthz + SDK 設定）</a></strong> のフローに従い、少なくとも一度 <code>GET /healthz</code> を検証します。</p><p><strong>表示されるべきもの</strong>：<code>/healthz</code> が成功を返す（サービスが使用可能であることを確認するために使用されます）。</p><h2 id="最近のバージョンの要約-readme-から抜粋" tabindex="-1">最近のバージョンの要約（README から抜粋） <a class="header-anchor" href="#最近のバージョンの要約-readme-から抜粋" aria-label="Permalink to &quot;最近のバージョンの要約（README から抜粋）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>バージョン</th><th>日付</th><th>気にするべき点</th></tr></thead><tbody><tr><td><code>v3.3.49</code></td><td>2026-01-22</td><td>思考中断と 0 Token 防御；<code>gemini-2.5-flash-lite</code> を削除し、カスタムマッピングを手動で置換するようリマインダー；言語/テーマなどの設定が即時反映される；監視ダッシュボードの強化；OAuth 互換性の向上</td></tr><tr><td><code>v3.3.48</code></td><td>2026-01-21</td><td>Windows プラットフォームでバックグラウンドプロセスをサイレント実行（コンソールの点滅を修正）</td></tr><tr><td><code>v3.3.47</code></td><td>2026-01-21</td><td>画像生成パラメータマッピングの強化（<code>size</code>/<code>quality</code>）；Cloudflared トンネルのサポート；マージ競合による起動失敗の修正；3 層漸進的コンテキスト圧縮</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">「今回の更新が自分に影響するかどうか」を素早く判断する方法</p><p>まずこの 2 種類の文章を探してください：</p><ul><li><strong>ユーザーリマインダー/あなたが変更する必要がある</strong>：例えば、特定のデフォルトモデルが削除され、カスタムマッピングを手動で調整する必要があることが明示的に名指しされている</li><li><strong>コア修正/互換性修正</strong>：例：0 Token、429、Windows 点滅、起動失敗など「あなたが使用できなくなる」問題</li></ul></div><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を表示</strong></summary><blockquote><p>更新時間：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>内容</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>README 内蔵 Changelog（バージョン進化）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/README.md#L324-L455" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>324-455</td></tr><tr><td>About ページにバージョン番号と「更新をチェック」ボタンを表示</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L821-L954" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>821-954</td></tr><tr><td>About ページ「更新をチェック」コマンドの返却構造</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L187-L215" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>187-215</td></tr><tr><td>自動更新通知（ダウンロードして再起動）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/UpdateNotification.tsx#L33-L96" target="_blank" rel="noreferrer"><code>src/components/UpdateNotification.tsx</code></a></td><td>33-96</td></tr><tr><td>現在のバージョン番号（ビルドメタデータ）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/package.json#L1-L4" target="_blank" rel="noreferrer"><code>package.json</code></a></td><td>1-4</td></tr></tbody></table></details>',34)])])}const p=a(n,[["render",l]]);export{b as __pageData,p as default};
